using System;
using System.Collections.Generic;
using System.IO;
using UnityEngine;
using UnityEngine.SceneManagement;

/// <summary>
/// Gestor central do sistema de save (singleton, mesmo padrão de
/// PlayerProgress/WorldState/GameVariables). Responsável por:
///
/// - Capturar o estado actual (PlayerProgress, WorldState, GameVariables,
///   FormSwitcher, cena/posição do player) numa <see cref="SaveData"/>.
/// - Restaurar esse estado a partir de uma SaveData carregada.
/// - Ler/escrever ficheiros JSON em disco, num slot de autosave (1) e até
///   <see cref="MaxManualSlots"/> slots manuais (0-29), conforme o esquema do
///   menu de save (1 slot automático no topo + até 30 manuais escolhidos pelo
///   jogador).
///
/// Não decide QUANDO gravar/carregar — isso é feito por SafeHaven (save
/// manual) e pelos triggers de entrada/saída de área/cidade (autosave), e pelo
/// SaveMenuController (escolha de slot no menu de save/load).
///
/// ⚠ ORDEM DE INICIALIZAÇÃO: <see cref="RestoreState"/> (e portanto
/// <see cref="LoadAutosave"/>/<see cref="LoadManualSlot"/>) NUNCA deve ser
/// chamado a partir de Awake(). Deve ser chamado em Start() ou mais tarde,
/// depois de todos os outros scripts terem corrido o seu Start() (em
/// particular FormSwitcher.Start(), que chama SyncFreedAnimalsFromProgress()).
/// O [DefaultExecutionOrder(100)] abaixo garante que o Start() deste script
/// corre depois dos sistemas de jogo (ordem por defeito = 0), prevenindo
/// conflitos caso algum sistema de boot carregue o save no Start() deste
/// componente. Se precisares de iniciar um load numa fase anterior, usa uma
/// coroutine com yield return null para esperar um frame.
/// </summary>
[DefaultExecutionOrder(100)]
public class SaveManager : MonoBehaviour
{
    public static SaveManager Instance { get; private set; }

    /// <summary>Número máximo de slots manuais (1-30, indexados 0-29).</summary>
    public const int MaxManualSlots = 30;

    private const string SaveFolderName = "Saves";
    private const string AutoSaveFileName = "save_auto.json";
    private const string ManualSaveFilePrefix = "save_slot_";
    private const string SaveFileExtension = ".json";

    /// <summary>Disparado depois de um save (autosave ou manual) ser escrito com sucesso. Argumento: slotIndex (-1 = auto).</summary>
    public event Action<int> OnSaveCompleted;

    /// <summary>Disparado depois de um load (autosave ou manual) ser aplicado com sucesso. Argumento: slotIndex (-1 = auto).</summary>
    public event Action<int> OnLoadCompleted;

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(SaveManager) + " (Fallback)");
        var instance = go.AddComponent<SaveManager>();
        instance.isAutoFallback = true;
    }

    // ---------------- Caminhos ----------------

    private string SaveDirectory => Path.Combine(Application.persistentDataPath, SaveFolderName);

    private string AutoSavePath => Path.Combine(SaveDirectory, AutoSaveFileName);

    private string ManualSavePath(int slotIndex) =>
        Path.Combine(SaveDirectory, $"{ManualSaveFilePrefix}{slotIndex:00}{SaveFileExtension}");

    private string PathForSlot(int slotIndex, bool isAuto) => isAuto ? AutoSavePath : ManualSavePath(slotIndex);

    // ---------------- Consultas de Slots ----------------

    public bool HasAutoSave() => SlotFileExists(AutoSavePath);

    public bool HasManualSave(int slotIndex)
    {
        if (slotIndex < 0 || slotIndex >= MaxManualSlots) return false;
        return SlotFileExists(ManualSavePath(slotIndex));
    }

    /// <summary>
    /// Um slot conta como usado se o ficheiro principal OU o backup .bak
    /// existir — mantém o menu coerente com ReadFromFile, que recupera do
    /// .bak quando o principal está ausente/corrompido (ex: crash a meio da
    /// rotação de ficheiros em WriteToFile).
    /// </summary>
    private static bool SlotFileExists(string path) =>
        File.Exists(path) || File.Exists(Path.ChangeExtension(path, ".bak"));

    /// <summary>Índices (0-29) dos slots manuais já usados, por ordem.</summary>
    public List<int> GetUsedManualSlots()
    {
        var used = new List<int>();
        for (int i = 0; i < MaxManualSlots; i++)
            if (HasManualSave(i)) used.Add(i);

        return used;
    }

    /// <summary>
    /// Primeiro slot manual livre (0-29), ou -1 se os 30 estiverem ocupados.
    /// Usado pelo botão "Criar novo save" do menu — esse botão fica escondido
    /// quando isto devolve -1.
    /// </summary>
    public int GetFirstFreeManualSlot()
    {
        for (int i = 0; i < MaxManualSlots; i++)
            if (!HasManualSave(i)) return i;

        return -1;
    }

    // ---------------- Versão actual do Schema ----------------

    /// <summary>
    /// Incrementar sempre que o schema de SaveData mudar de forma
    /// incompatível (campos renomeados/removidos/com tipo alterado).
    /// O campo SaveData.saveVersion é escrito em cada novo save e lido ao
    /// restaurar — se saveVersion &lt; CurrentSaveVersion, RestoreState avisa e
    /// pode aplicar lógica de migração.
    /// </summary>
    public const int CurrentSaveVersion = 1;

    // ---------------- Captura / Restauro de Estado ----------------

    /// <summary>Constrói uma SaveData com o estado actual do jogo.</summary>
    public SaveData CaptureState(int slotIndex, bool isAuto)
    {
        var data = new SaveData
        {
            slotIndex = slotIndex,
            isAutosave = isAuto,
            saveVersion = CurrentSaveVersion,
            timestamp = DateTime.UtcNow.ToString("o"),
            sceneName = SceneManager.GetActiveScene().name
        };

        var playerT = PlayerLocator.Find();
        if (playerT != null)
        {
            var pos = playerT.position;
            data.playerPosX = pos.x;
            data.playerPosY = pos.y;
            data.playerPosZ = pos.z;
        }

        PlayerProgress.Instance?.CaptureTo(data);
        WorldState.Instance?.CaptureTo(data);
        GameVariables.Instance?.CaptureTo(data);

        var formSwitcher = playerT != null ? playerT.GetComponent<FormSwitcher>() : null;
        formSwitcher?.CaptureTo(data);

        return data;
    }

    /// <summary>
    /// Aplica o estado guardado em "data" aos singletons relevantes e
    /// reposiciona o player. Não trata de mudança de cena — chamar depois de a
    /// cena de "data.sceneName" estar carregada.
    /// </summary>
    public void RestoreState(SaveData data)
    {
        if (data == null) return;

        // Verificação de versão: avisa se o save é mais antigo que o schema actual.
        // Adicionar lógica de migração aqui conforme o jogo evolui.
        if (data.saveVersion < CurrentSaveVersion)
            Debug.LogWarning(
                $"[SaveManager] Save versão {data.saveVersion} (actual: {CurrentSaveVersion}). " +
                $"Campos novos ficarão em valores padrão. Se ocorrerem comportamentos inesperados, " +
                $"cria um novo save.");

        PlayerProgress.Instance?.RestoreFrom(data);
        WorldState.Instance?.RestoreFrom(data);
        GameVariables.Instance?.RestoreFrom(data);

        var playerT = PlayerLocator.Find();
        var formSwitcher = playerT != null ? playerT.GetComponent<FormSwitcher>() : null;
        formSwitcher?.RestoreFrom(data);

        if (playerT != null)
        {
            // Limpar estados físicos e temporários antes de reposicionar (Task 2.3).
            // Impede que dash, stun, locks de armadilhas ou velocidade residual
            // se propaguem para a cena/posição carregada.
            playerT.GetComponent<PlayerCombat>()?.ForceEndStun();
            playerT.GetComponent<PlayerMotor2D>()?.ClearAllMovementLocks();

            var rb = playerT.GetComponent<Rigidbody2D>();
            if (rb != null)
            {
                rb.linearVelocity = Vector2.zero;
                rb.angularVelocity = 0f;
                rb.position = new Vector2(data.playerPosX, data.playerPosY);
            }
            else
            {
                playerT.position = new Vector3(data.playerPosX, data.playerPosY, data.playerPosZ);
            }

            Physics2D.SyncTransforms();
        }
    }

    // ---------------- Gravar ----------------

    /// <summary>Grava o autosave (chamado ao entrar/sair de área ou cidade — Etapa de Safe Haven/Autosave).</summary>
    public bool SaveAutosave()
    {
        return WriteToFile(CaptureState(-1, true), AutoSavePath);
    }

    /// <summary>Grava num slot manual (0-29), tipicamente a partir de um Safe Haven ou do menu de save.</summary>
    public bool SaveToManualSlot(int slotIndex)
    {
        if (slotIndex < 0 || slotIndex >= MaxManualSlots)
        {
            Debug.LogError($"[SaveManager] Slot manual inválido: {slotIndex}");
            return false;
        }

        return WriteToFile(CaptureState(slotIndex, false), ManualSavePath(slotIndex));
    }

    private bool WriteToFile(SaveData data, string path)
    {
        string tmpPath = path + ".tmp";
        string bakPath = Path.ChangeExtension(path, ".bak");

        try
        {
            Directory.CreateDirectory(SaveDirectory);

            string json = JsonUtility.ToJson(data, true);

            // Validação: garante que o JSON é parseável antes de tocar no ficheiro final.
            JsonUtility.FromJson<SaveData>(json);

            // 1. Escrever no temporário.
            File.WriteAllText(tmpPath, json);

            // 2. Rodar: ficheiro actual → .bak, temporário → ficheiro final.
            if (File.Exists(path))
            {
                if (File.Exists(bakPath)) File.Delete(bakPath);
                File.Move(path, bakPath);
            }
            File.Move(tmpPath, path);

            OnSaveCompleted?.Invoke(data.slotIndex);
            return true;
        }
        catch (Exception e)
        {
            Debug.LogError($"[SaveManager] Falha ao gravar '{path}': {e}");
            // Limpar .tmp órfão se a escrita falhou antes do Move.
            try { if (File.Exists(tmpPath)) File.Delete(tmpPath); } catch { }
            return false;
        }
    }

    // ---------------- Carregar ----------------

    /// <summary>Lê e aplica o autosave. Devolve false se não existir ou falhar.</summary>
    public bool LoadAutosave()
    {
        var data = ReadFromFile(AutoSavePath);
        if (data == null) return false;

        RestoreState(data);
        OnLoadCompleted?.Invoke(-1);
        return true;
    }

    /// <summary>Lê e aplica um slot manual (0-29). Devolve false se não existir ou falhar.</summary>
    public bool LoadManualSlot(int slotIndex)
    {
        if (slotIndex < 0 || slotIndex >= MaxManualSlots) return false;

        var data = ReadFromFile(ManualSavePath(slotIndex));
        if (data == null) return false;

        RestoreState(data);
        OnLoadCompleted?.Invoke(slotIndex);
        return true;
    }

    /// <summary>
    /// Lê os metadados de um slot (timestamp, cena, recursos, % etc.) sem
    /// aplicar o estado ao jogo — usado pelo menu de save para desenhar os
    /// botões de slot (preview). Devolve null se o slot não existir.
    /// </summary>
    public SaveData PeekSlot(int slotIndex, bool isAuto)
    {
        return ReadFromFile(PathForSlot(slotIndex, isAuto));
    }

    private SaveData ReadFromFile(string path)
    {
        var data = TryReadFile(path, logErrors: true);
        if (data != null) return data;

        // Recuperação: se o ficheiro principal não existe ou está corrompido,
        // tenta o backup .bak escrito por WriteToFile na gravação anterior.
        string bakPath = Path.ChangeExtension(path, ".bak");
        if (File.Exists(bakPath))
        {
            data = TryReadFile(bakPath, logErrors: true);
            if (data != null)
            {
                Debug.LogWarning($"[SaveManager] '{path}' indisponível/corrompido — restaurado a partir do backup '{bakPath}'.");
                return data;
            }
        }

        return null;
    }

    private static SaveData TryReadFile(string path, bool logErrors)
    {
        try
        {
            if (!File.Exists(path)) return null;

            string json = File.ReadAllText(path);
            var data = JsonUtility.FromJson<SaveData>(json);
            if (data == null && logErrors)
                Debug.LogError($"[SaveManager] Conteúdo inválido em '{path}'.");
            return data;
        }
        catch (Exception e)
        {
            if (logErrors) Debug.LogError($"[SaveManager] Falha ao ler '{path}': {e}");
            return null;
        }
    }

    // ---------------- Apagar ----------------

    /// <summary>
    /// Apaga um slot manual (0-29). Liberta o slot para reutilização e pode
    /// fazer reaparecer o botão "Criar novo save" no menu (se estava escondido
    /// por os 30 estarem ocupados).
    /// </summary>
    public bool DeleteManualSlot(int slotIndex)
    {
        if (slotIndex < 0 || slotIndex >= MaxManualSlots) return false;

        string path = ManualSavePath(slotIndex);
        string bakPath = Path.ChangeExtension(path, ".bak");
        if (!File.Exists(path) && !File.Exists(bakPath)) return false;

        try
        {
            if (File.Exists(path)) File.Delete(path);
            // Apagar também o backup — sem isto o slot continuaria a contar
            // como usado (SlotFileExists) e reapareceria no menu.
            if (File.Exists(bakPath)) File.Delete(bakPath);
            return true;
        }
        catch (Exception e)
        {
            Debug.LogError($"[SaveManager] Falha ao apagar '{path}': {e}");
            return false;
        }
    }
}
